SELECT tp.param_id, tp.param_name, pv.version_id, pv.version_number
FROM timing_parameters tp
JOIN param_versions pv ON tp.param_id = pv.param_id;

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN param_versions pv ON u.user_id = pv.changed_by;

SELECT tp.param_name, tp.param_id
FROM timing_parameters tp
JOIN param_versions pv ON tp.param_id = pv.param_id;

SELECT param_name, description 
FROM timing_parameters 
WHERE min_value > 10;

SELECT COUNT(DISTINCT changed_by) 
FROM param_versions 
WHERE approved_by IS NULL;

SELECT param_name, description
FROM timing_parameters
ORDER BY param_name ASC;

SELECT *
FROM timing_parameters
ORDER BY param_name ASC;

SELECT tp.param_name, c.component_name
FROM timing_parameters AS tp
JOIN components AS c ON tp.component = c.component_name;

SELECT COUNT(*) AS num_changed_params
FROM param_versions pv
WHERE pv.changed_by = '0';

SELECT *
FROM param_versions
WHERE changed_by = '1';

SELECT tp.param_id, tp.param_name, tp.description 
FROM timing_parameters tp 
WHERE tp.component = 1;
